-- First, let's see which heroes we have in the old data
-- SELECT DISTINCT hero_id FROM _old_mlbb_player_stats_migration;

INSERT INTO stats_mlbb_game_player (
  player_id,
  game_id,
  team_id,
  hero_name,
  kills,
  deaths,
  assists,
  gold,
  damage_dealt,
  turret_damage,
  damage_taken,
  rating,
  is_mvp,
  teamfight,
  turtle_slain,
  lord_slain,
  created_at
)
SELECT 
  ps.player_id,
  mg.new_game_id,
  p.team_id, -- Use team_id from the players table if available
  NULL AS hero_name, -- Cannot resolve old UUID-based hero_id to new game_characters
  ps.kills::INTEGER,
  ps.deaths::INTEGER,
  ps.assists::INTEGER,
  ps.net_worth::INTEGER,
  ps.hero_dmg::INTEGER,
  ps.turret_dmg::INTEGER,
  ps.dmg_tkn::INTEGER,
  ps.rating::NUMERIC,
  ps.is_mvp::BOOLEAN,
  ps.teamfight::INTEGER,
  ps.turtle_slain::INTEGER,
  ps.lord_slain::INTEGER,
  ps.created_at
FROM _old_mlbb_player_stats_migration ps
JOIN _migration_mlbb_games mg ON mg.old_game_id = ps.match_id
LEFT JOIN players p ON p.id = ps.player_id
WHERE NOT EXISTS (
  SELECT 1 FROM stats_mlbb_game_player smgp
  WHERE smgp.player_id = ps.player_id AND smgp.game_id = mg.new_game_id
);

-- ============================================================================
-- Step 5: Migrate Valorant player stats to new table
-- ============================================================================

INSERT INTO stats_valorant_game_player (
  player_id,
  game_id,
  team_id,
  agent_name,
  acs,
  kills,
  deaths,
  assists,
  first_bloods,
  econ_rating,
  plants,
  defuses,
  is_mvp,
  created_at
)
SELECT 
  ps.player_id,
  mg.new_game_id,
  p.team_id, -- Use team_id from the players table if available
  NULL AS agent_name, -- Cannot resolve old UUID-based agent_id to new game_characters
  ps.acs::INTEGER,
  ps.kills::INTEGER,
  ps.deaths::INTEGER,
  ps.assists::INTEGER,
  ps.first_bloods::INTEGER,
  ps.econ_rating::INTEGER,
  ps.plants::INTEGER,
  ps.defuses::INTEGER,
  ps.is_mvp::BOOLEAN,
  ps.created_at
FROM _old_valo_player_stats_migration ps
JOIN _migration_valo_games mg ON mg.old_game_id = ps.match_id
LEFT JOIN players p ON p.id = ps.player_id
WHERE NOT EXISTS (
  SELECT 1 FROM stats_valorant_game_player svgp
  WHERE svgp.player_id = ps.player_id AND svgp.game_id = mg.new_game_id
);

-- ============================================================================
-- Step 6: Verification
-- ============================================================================

-- Count records
SELECT 'MLBB staging records' as type, COUNT(*) as count FROM _old_mlbb_player_stats_migration
UNION ALL
SELECT 'Valorant staging records' as type, COUNT(*) FROM _old_valo_player_stats_migration
UNION ALL
SELECT 'MLBB migrated stats' as type, COUNT(*) FROM stats_mlbb_game_player
UNION ALL
SELECT 'Valorant migrated stats' as type, COUNT(*) FROM stats_valorant_game_player;

-- Sample MLBB stats
SELECT 
  p.ign as player_name,
  smgp.hero_name,
  smgp.kills,
  smgp.deaths,
  smgp.assists,
  smgp.gold,
  smgp.damage_dealt
FROM stats_mlbb_game_player smgp
JOIN players p ON p.id = smgp.player_id
ORDER BY smgp.kills DESC
LIMIT 10;

-- Sample Valorant stats
SELECT 
  p.ign as player_name,
  svgp.agent_name,
  svgp.acs,
  svgp.kills,
  svgp.deaths,
  svgp.assists,
  svgp.first_bloods
FROM stats_valorant_game_player svgp
JOIN players p ON p.id = svgp.player_id
ORDER BY svgp.acs DESC
LIMIT 10;

-- Note: Hero/agent name resolution was skipped during migration
-- Old data used UUID-based hero_id/agent_id which cannot be matched to new game_characters (smallint id)
-- Hero and agent names in migrated stats are set to NULL
